using System.ComponentModel.DataAnnotations;using System.ComponentModel.DataAnnotations.Schema;using Microsoft.EntityFrameworkCore;namespace CollegeManagementSystem.Data.Entities;[Table("Enrollments")][PrimaryKey(nameof(StudentId), nameof(CourseId))]public class Enrollment{    [ForeignKey("Student")] public int StudentId { get; set; }    [ForeignKey("Course")] public int CourseId { get; set; }    public Student Student { get; set; } = null!;    public Course Course { get; set; } = null!;    [Required] public DateTime EnrolledDate { get; set; }}